namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public List<int> Ratings { get; set; } = new();

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1,
            Title = "Classic Margherita Pizza",
            Category = "Italian",
            Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
            Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil."
        },
        new Recipe
        {
            Id = 2,
            Title = "Spaghetti Carbonara",
            Category = "Italian",
            Ingredients = "Spaghetti\nGuanciale (or pancetta)\nEggs\nPecorino Romano\nBlack pepper",
            Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan over medium heat.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat and stir in egg mixture quickly.\n6. Serve immediately with extra pecorino."
        },
        new Recipe
        {
            Id = 3,
            Title = "Chicken Tikka Masala",
            Category = "Indian",
            Ingredients = "Chicken thighs\nYogurt\nGaram masala\nTurmeric\nCumin\nCrushed tomatoes\nHeavy cream\nGarlic\nGinger\nOnion",
            Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger in a pan.\n4. Add crushed tomatoes and simmer 15 minutes.\n5. Stir in cream and garam masala.\n6. Add chicken pieces and simmer 10 minutes.\n7. Serve over basmati rice."
        },
        new Recipe
        {
            Id = 4,
            Title = "Vegetable Pad Thai",
            Category = "Thai",
            Ingredients = "Rice noodles\nTofu\nBean sprouts\nScallions\nPeanuts\nLime\nTamarind paste\nFish sauce\nSugar\nChili flakes",
            Steps = "1. Soak rice noodles in warm water 20 minutes.\n2. Press and cube tofu, then pan-fry until golden.\n3. Mix tamarind paste, fish sauce, sugar, and chili.\n4. Stir-fry noodles with sauce until coated.\n5. Add tofu and bean sprouts.\n6. Serve with crushed peanuts, scallions, and lime."
        },
        new Recipe
        {
            Id = 5,
            Title = "Beef Tacos",
            Category = "Mexican",
            Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa",
            Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Assemble tacos with beef, lettuce, tomato, cheese.\n5. Top with sour cream and salsa."
        },
        new Recipe
        {
            Id = 6,
            Title = "Chocolate Lava Cake",
            Category = "Desserts",
            Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
            Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick.\n4. Fold in chocolate mixture, then flour.\n5. Pour into greased ramekins.\n6. Bake 12-14 minutes (center should be soft).\n7. Invert onto plates and serve immediately."
        }
    };

    public List<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public List<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int rating)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe != null && rating >= 1 && rating <= 5)
        {
            recipe.Ratings.Add(rating);
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }
}

