toolArgs.file_text:
@page "/recipes/category/{CategoryName}"

<PageTitle>@CategoryName Recipes - Recipe Community</PageTitle>

<div class="container py-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1 class="mb-4">@CategoryName Recipes</h1>

    @if (_recipes.Count == 0)
    {
        <div class="alert alert-info">No recipes found in this category.</div>
    }
    else
    {
        <div class="row g-4">
            @foreach (var recipe in _recipes)
            {
                <div class="col-md-6">
                    <div class="card h-100 shadow-sm">
                        <div class="card-body">
                            <h4 class="card-title">@recipe.Title</h4>
                            <p class="card-text text-muted">
                                @if (recipe.Ratings.Count > 0)
                                {
                                    <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.Ratings.Count ratings)</span>
                                }
                                else
                                {
                                    <span>No ratings yet</span>
                                }
                            </p>
                            <a href="/recipes/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private Services.RecipeService RecipeService { get; set; } = default!;

    private List<Models.Recipe> _recipes = new();

    protected override void OnInitialized()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipes/{Id:int}"

<PageTitle>@(_recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

<div class="container py-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (_recipe != null)
            {
                <li class="breadcrumb-item"><a href="/recipes/category/@_recipe.Category">@_recipe.Category</a></li>
                <li class="breadcrumb-item active">@_recipe.Title</li>
            }
        </ol>
    </nav>

    @if (_recipe == null)
    {
        <div class="alert alert-warning">Recipe not found.</div>
    }
    else
    {
        <h1 class="mb-2">@_recipe.Title</h1>
        <p class="text-muted mb-4">
            Category: <a href="/recipes/category/@_recipe.Category">@_recipe.Category</a>
            @if (_recipe.Ratings.Count > 0)
            {
                <span class="ms-3">⭐ @_recipe.AverageRating.ToString("F1") (@_recipe.Ratings.Count ratings)</span>
            }
        </p>

        <div class="row">
            <div class="col-md-4">
                <div class="card mb-4">
                    <div class="card-header"><h5 class="mb-0">🧂 Ingredients</h5></div>
                    <div class="card-body">
                        <ul class="list-unstyled mb-0">
                            @foreach (var ingredient in _recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                            {
                                <li class="mb-1">• @ingredient</li>
                            }
                        </ul>
                    </div>
                </div>
            </div>
            <div class="col-md-8">
                <div class="card mb-4">
                    <div class="card-header"><h5 class="mb-0">📋 Steps</h5></div>
                    <div class="card-body">
                        @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <p class="mb-2">@step</p>
                        }
                    </div>
                </div>
            </div>
        </div>

        <RecipeCommunity.Components.Shared.StarRating RecipeId="@_recipe.Id"
            AverageRating="@_recipe.AverageRating"
            RatingCount="@_recipe.Ratings.Count" />
    }
</div>

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private Services.RecipeService RecipeService { get; set; } = default!;

    private Models.Recipe? _recipe;

    protected override void OnInitialized()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/recipes/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container py-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1 class="mb-4">📝 Submit Your Recipe</h1>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4>Recipe submitted successfully!</h4>
            <p>Your recipe "<strong>@_title</strong>" has been added to the community.</p>
            <a href="/recipes/category/@_category" class="btn btn-primary">View in @_category</a>
            <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
        </div>
    }
    else
    {
        <EditForm Model="@this" OnValidSubmit="HandleSubmit" FormName="recipe-form">
            <div class="row">
                <div class="col-md-8">
                    <div class="mb-3">
                        <label for="title" class="form-label">Recipe Title</label>
                        <InputText id="title" class="form-control" @bind-Value="_title"
                                   placeholder="e.g., Grandma's Apple Pie" required />
                    </div>

                    <div class="mb-3">
                        <label for="category" class="form-label">Category</label>
                        <InputSelect id="category" class="form-select" @bind-Value="_category">
                            <option value="">-- Select a category --</option>
                            <option value="Italian">Italian</option>
                            <option value="Indian">Indian</option>
                            <option value="Thai">Thai</option>
                            <option value="Mexican">Mexican</option>
                            <option value="Desserts">Desserts</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>

                    <div class="mb-3">
                        <label for="ingredients" class="form-label">Ingredients</label>
                        <InputTextArea id="ingredients" class="form-control" rows="6"
                                       @bind-Value="_ingredients"
                                       placeholder="Enter each ingredient on a new line" required />
                        <div class="form-text">One ingredient per line</div>
                    </div>

                    <div class="mb-3">
                        <label for="steps" class="form-label">Steps</label>
                        <InputTextArea id="steps" class="form-control" rows="8"
                                       @bind-Value="_steps"
                                       placeholder="Enter each step on a new line (e.g., 1. Preheat oven...)" required />
                        <div class="form-text">One step per line</div>
                    </div>

                    @if (!string.IsNullOrEmpty(_error))
                    {
                        <div class="alert alert-danger">@_error</div>
                    }

                    <button type="submit" class="btn btn-success btn-lg">Submit Recipe</button>
                </div>
            </div>
        </EditForm>
    }
</div>

@code {
    [Inject] private Services.RecipeService RecipeService { get; set; } = default!;

    private string _title = string.Empty;
    private string _category = string.Empty;
    private string _ingredients = string.Empty;
    private string _steps = string.Empty;
    private string _error = string.Empty;
    private bool _submitted;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_title) || string.IsNullOrWhiteSpace(_category)
            || string.IsNullOrWhiteSpace(_ingredients) || string.IsNullOrWhiteSpace(_steps))
        {
            _error = "Please fill in all fields.";
            return;
        }

        var recipe = new Models.Recipe
        {
            Title = _title.Trim(),
            Category = _category,
            Ingredients = _ingredients.Trim(),
            Steps = _steps.Trim()
        };

        RecipeService.AddRecipe(recipe);
        _submitted = true;
        _error = string.Empty;
    }

    private void Reset()
    {
        _title = string.Empty;
        _category = string.Empty;
        _ingredients = string.Empty;
        _steps = string.Empty;
        _submitted = false;
        _error = string.Empty;
    }
}

